#!/usr/bin/env node

import { readFileSync, writeFileSync, readdirSync } from "node:fs";
import { dirname, join, basename } from "node:path";
import { fileURLToPath } from "node:url";

import { loadConfig } from "./lib/config.mjs";

const __dirname = dirname(fileURLToPath(import.meta.url));
const REPO_ROOT = join(__dirname, "..", "..");
const TEMPLATE_DIR = join(__dirname, "templates");
const OUT_DIR = join(REPO_ROOT, ".github", "ISSUE_TEMPLATE");

const HEADER = [
  "# This file is GENERATED by scripts/pipeline/generate-templates.mjs.",
  "# Do not edit by hand. Edit .github/pipeline-config.yml or the skeleton at",
  "# scripts/pipeline/templates/, then run `make pipeline-generate`.",
  "",
].join("\n");

function formatOptions(items, indent) {
  // Convert ["alpha", "beta"] → "  - alpha\n  - beta" with given indent
  return items.map((i) => `${indent}- ${i}`).join("\n");
}

export function buildTemplate(skeleton, config) {
  const domains = (config.domains ?? []).map((d) => d.name);
  const components = (config.components ?? []).map((c) => c.name);

  // Replace placeholders. The placeholder sits on the same line as `options:` so
  // we need to insert a newline + indented list after `options:`.
  let out = skeleton.replace(
    /^(\s*)options:\s*__DOMAIN_OPTIONS__\s*$/gm,
    (_, indent) => `${indent}options:\n${formatOptions(domains, `${indent}  `)}`,
  );
  out = out.replace(
    /^(\s*)options:\s*__COMPONENT_OPTIONS__\s*$/gm,
    (_, indent) => `${indent}options:\n${formatOptions(components, `${indent}  `)}`,
  );

  return HEADER + out;
}

if (process.argv[1]?.endsWith("/generate-templates.mjs")) {
  const configPath = process.argv[2] || join(REPO_ROOT, ".github", "pipeline-config.yml");
  const outDir = process.argv[3] || OUT_DIR;
  const config = loadConfig(configPath);

  const skeletonFiles = readdirSync(TEMPLATE_DIR).filter((f) => f.endsWith(".yml.template"));
  for (const file of skeletonFiles) {
    const skeleton = readFileSync(join(TEMPLATE_DIR, file), "utf8");
    const out = buildTemplate(skeleton, config);
    const outName = basename(file).replace(/\.template$/, "");
    writeFileSync(join(outDir, outName), out);
    console.log(`Wrote ${outDir}/${outName}`);
  }
}
